% X1: 学历（1=专科,2=本科,3=硕士,4=博士）
% X2: 职称（1=未定,2=初级,3=中级,4=副高,5=正高）
% X3: 年龄
% Y: 数字胜任力评分
% 生成虚构数据
rng(42); % 设置随机种子
n = 1000;
X1 = randi([1 4], n, 1); % 学历
X2 = randi([1 5], n, 1); % 职称
X3 = randi([25 65], n, 1); % 年龄
Y = 60 + 5*X1 + 3*X2 - 0.1*X3 + 5*randn(n,1); % 数字胜任力评分
% 4.2 多元线性回归
X = [ones(n,1), X1, X2, X3]; % 设计矩阵
[b, bint, r, rint, stats] = regress(Y, X);
% 显示回归结果
fprintf('回归结果:\n');
fprintf('截距: %.2f (95%% CI: %.2f-%.2f)\n', b(1), bint(1,1), bint(1,2));
fprintf('学历系数: %.2f (95%% CI: %.2f-%.2f)\n', b(2), bint(2,1), bint(2,2));
fprintf('职称系数: %.2f (95%% CI: %.2f-%.2f)\n', b(3), bint(3,1), bint(3,2));
fprintf('年龄系数: %.2f (95%% CI: %.2f-%.2f)\n', b(4), bint(4,1), bint(4,2));

