%% 6. 分组比较（性别差异）
% 使用t 检验比较男女教师在数字胜任力上的差异
% 生成虚构数据
male_comp = 75 + 5*randn(sum(X3<=35 & X1>=3),1); % 年轻高学历男教师
female_comp = 70 + 5*randn(sum(X3<=35 & X1>=3),1); % 年轻高学历女教
师
% 执行t 检验
[h, p, ci, stats] = ttest2(male_comp, female_comp);
fprintf('\n 性别差异比较(年轻高学历教师):\n');
fprintf('男教师平均数字胜任力: %.2f\n', mean(male_comp));
fprintf('女教师平均数字胜任力: %.2f\n', mean(female_comp));
fprintf('t 统计量: %.2f, p 值: %.4f\n', stats.tstat, p);
if h
fprintf('差异显著(p < 0.05)\n');
else
fprintf('差异不显著(p >= 0.05)\n');
end
%% 补充分析：各因素贡献度计算
% 计算标准化回归系数以比较各因素相对重要性
X_normalized = zscore([X1, X2, X3]);
mdl = fitlm(X_normalized, Y);
std_coeff = mdl.Coefficients.Estimate(2:end);
figure;
bar(std_coeff);

